import "../styles/Home.css";
import Navbar from "../components/Navbar";

function Home() {
  return (
    <div className="home-container">

      <Navbar />

      <div className="home-content">

        <div>
          <h1 className="home-title">
            Bienvenido
          </h1>

          <p className="home-text">
            Aprender es crecer un poco cada día.
          </p>
        </div>

      </div>

    </div>
  );
}

export default Home;
